const n = $input.first().json.topics.length; // total number of topics
const count = 4; // number of random numbers to select

// Safety check to prevent an infinite loop if you have fewer than 4 topics
const actualCount = Math.min(count, n);

const randomNumbers = new Set();
while (randomNumbers.size < actualCount) {
  // Math.random() is allowed by default and works great here
  randomNumbers.add(Math.floor(Math.random() * n));
}

return [{ json: { randomNumbers: Array.from(randomNumbers) } }];

